SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

CREATE OR REPLACE VIEW view_sctransdivagn (data_code, bank_code, trandate, seq_tran, seq_no, membership_no, cmember_name, amount, acc_no, member_group_no, c_reference, eng_name, item_type, branch_bank_code, fee_amount, begining_of_contract, branch_id, loan_type, trans_bank_status, item_seq_no, account_year, group_pay_code) AS SELECT
        ' ' as data_code,  
        '006' as bank_code , 
        ' ' as trandate,  
        ' ' as seq_tran,  
        0 as seq_no,
        sc_mem_m_ucf_member_group.member_group_control as membership_no ,     
        pka_com_function.fp_get_group_name( sc_mem_m_ucf_member_group.member_group_control ) as cmember_name ,
        sum( sc_mem_m_capital_pay.item_amount ) as amount,
        sc_mem_m_capital_pay_agn.bank_acc_no as acc_no,
        sc_mem_m_ucf_member_group.member_group_control as member_group_no,
        sc_mem_m_capital_pay.account_year as c_reference,
        '' as eng_name ,
        'DIV' as item_type,
        left((trim(both sc_mem_m_capital_pay_agn.bank_acc_no)),3) as branch_bank_code,
        0 as fee_amount,
        sc_acc_m_account_year.beginning_of_account  as begining_of_contract
,'01' as branch_id
,sc_mem_m_capital_pay.group_pay_code as loan_type
,'0' as trans_bank_status
,0 as item_seq_no
,sc_acc_m_account_year.account_year 
,sc_mem_m_capital_pay.group_pay_code  
FROM 
   sc_mem_m_capital_pay_agn ,
    sc_mem_m_capital_stock_detail,
    sc_mem_m_ucf_member_group,
    sc_mem_m_capital_pay
  ,sc_acc_m_account_year
where 1=1
    and sc_mem_m_capital_stock_detail.member_group_no = sc_mem_m_ucf_member_group.member_group_no
    and sc_mem_m_capital_stock_detail.ending_balance > 0 
    and sc_mem_m_capital_pay.account_year = sc_mem_m_capital_stock_detail.account_year 
    and sc_mem_m_capital_pay.membership_no = sc_mem_m_capital_stock_detail.membership_no 
    and	sc_mem_m_capital_pay.item_amount > 0 
    and sc_acc_m_account_year.account_year = sc_mem_m_capital_pay.account_year

and sc_acc_m_account_year.account_year = sc_mem_m_capital_pay_agn.account_year
and sc_mem_m_capital_stock_detail.member_group_no = sc_mem_m_ucf_member_group.member_group_no 
and  sc_mem_m_capital_pay_agn.member_group_no =sc_mem_m_ucf_member_group.member_group_control  


/*WHERE*/

--and sc_acc_m_account_year.account_year = 2023
--and sc_mem_m_capital_pay.group_pay_code  = 'AG1'
group by sc_acc_m_account_year.account_year 
,sc_mem_m_capital_pay.group_pay_code  
,sc_mem_m_ucf_member_group.member_group_control
,sc_mem_m_capital_pay_agn.bank_acc_no
,sc_mem_m_capital_pay.account_year
,sc_acc_m_account_year.beginning_of_account 
order by 
    sc_mem_m_ucf_member_group.member_group_control  asc;

